`app/page.js` (HomePage); // Add a semicolon here
'use client';

import { useState, useEffect, useRef } from 'react';
import Image from 'next/image';
import './Homepage.css';

export default function HomePage() {
  const [activeLink, setActiveLink] = useState('discover');
  const [isMainContainerShow, setIsMainContainerShow] = useState(false);
  const [currentVideo, setCurrentVideo] = useState(null);
  const videoRefs = useRef({});

  useEffect(() => {
    const handleResize = () => {
      const sidebar = document.querySelector('.sidebar');
      if (window.innerWidth > 1090) {
        sidebar.classList.remove('collapse');
      } else {
        sidebar.classList.add('collapse');
      }
    };

    window.addEventListener('resize', handleResize);
    handleResize();

    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleSidebarLinkClick = (link) => {
    setActiveLink(link);
    if (link === 'discover') {
      setIsMainContainerShow(false);
    }
  };

  const handleVideoHover = (videoId, action) => {
    const videoElement = videoRefs.current[videoId];
    if (videoElement) {
      action === 'play' ? videoElement.play() : videoElement.pause();
    }
  };

  const handleVideoClick = (video) => {
    setCurrentVideo(video);
    setIsMainContainerShow(true);
    setActiveLink('trending');
  };

  return (
    <div className="container">
      <div className="sidebar">
        <span className="logo">S</span>
        <a className="logo-expand" href="#">skateboard</a>
        <div className="side-wrapper">
          <div className="side-title">MENU</div>
          <div className="side-menu">
            {['discover', 'trending', 'streaming', 'playlist', 'bookmark'].map(link => (
              <a 
                key={link}
                href="#" 
                className={`sidebar-link ${link} ${activeLink === link ? 'is-active' : ''}`}
                onClick={() => handleSidebarLinkClick(link)}
              >
                {link.charAt(0).toUpperCase() + link.slice(1)}
              </a>
            ))}
          </div>
        </div>
        <div className="side-wrapper">
          <div className="side-title">CATEGORY</div>
          <div className="side-menu">
            {['Live Stream', 'Tutorial', 'Competition', 'Community'].map((category, index) => (
              <a key={index} className="sidebar-link" href="#">
                {category}
              </a>
            ))}
          </div>
        </div>
      </div>
      <div className="wrapper">
        <div className="header">
          <div className="search-bar">
            <input type="text" placeholder="Search" />
          </div>
          <div className="user-settings">
            <Image 
              src="https://images.unsplash.com/photo-1587918842454-870dbd18261a" 
              alt="User" 
              width={40} 
              height={40} 
              className="user-img" 
            />
            <div className="user-name">Thomas</div>
            <div className="notify">
              <div className="notification"></div>
            </div>
          </div>
        </div>
        <div className={`main-container ${isMainContainerShow ? 'show' : ''}`}>
          <div className="main-header anim">Discover</div>
          <div className="main-blogs">
            {[
              {
                title: "How to do Basic Jumping and how to landing safely",
                author: "Thomas Hope",
                time: "7 min"
              },
              {
                title: "Skateboard Tips You need to know",
                author: "Tony Andrew",
                time: "7 min"
              }
            ].map((blog, index) => (
              <div key={index} className="main-blog anim">
                <div className="main-blog__title">{blog.title}</div>
                <div className="main-blog__author">
                  <div className="author-img__wrapper">
                    <Image 
                      src="https://images.unsplash.com/photo-1560941001-d4b52ad00ecc" 
                      alt={blog.author} 
                      width={40} 
                      height={40} 
                      className="author-img" 
                    />
                  </div>
                  <div className="author-detail">
                    <div className="author-name">{blog.author}</div>
                    <div className="author-info">53K views <span className="seperate"></span>2 weeks ago</div>
                  </div>
                </div>
                <div className="main-blog__time">{blog.time}</div>
              </div>
            ))}
          </div>
          <div className="small-header anim">Most Watched</div>
          <div className="videos">
            {[
              {
                id: 1,
                time: '8 min',
                videoSrc: 'https://player.vimeo.com/external/436572488.sd.mp4?s=eae5fb490e214deb9ff532dd98d101efe94e7a8b&profile_id=139&oauth2_token_id=57447761',
                authorImg: 'https://images.pexels.com/photos/1680172/pexels-photo-1680172.jpeg?auto=compress&cs=tinysrgb&dpr=2&w=500',
                videoBy: 'Andy William',
                videoName: 'Basic how to ride your skateboard comfortably'
              }
              // Add more videos as needed
            ].map(video => (
              <div 
                key={video.id} 
                className="video" 
                onMouseEnter={() => handleVideoHover(video.id, 'play')}
                onMouseLeave={() => handleVideoHover(video.id, 'pause')}
                onClick={() => handleVideoClick(video)}
              >
                <div className="video-time">{video.time}</div>
                <div className="video-wrapper">
                  <video 
                    ref={el => videoRefs.current[video.id] = el} 
                    muted 
                    src={video.videoSrc}
                  />
                  <div className="author-img__wrapper video-author">
                    <Image 
                      src={video.authorImg} 
                      alt={video.videoBy} 
                      width={50} 
                      height={50} 
                      className="author-img" 
                    />
                  </div>
                </div>
                <div className="video-by">{video.videoBy}</div>
                <div className="video-name">{video.videoName}</div>
                <div className="video-view">54K views<span className="seperate video-seperate"></span>1 week ago</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
